INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-d35ec6db-moex-00067', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲向乙承租房屋一棟。依民法規定，下列敘述何者錯誤？', '["若甲、乙間未為反對之約定，甲逕行將該屋中之一間房間轉租於丙，則乙得終止該租賃契約", "若雙方約定租期為3年，但未以字據訂立，則甲、乙間之租賃契約未定期限", "若甲向乙所承租之房屋為海砂屋，則甲得主張終止該租賃契約", "若甲與乙間之租賃契約約定之租期為1年，則乙不得隨時終止該租賃契約 20320 20420"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00068', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '就甲、乙、丙三人對丁負有新臺幣（下同）90萬元連帶債務之情形，下列敘述何者正確？', '["甲向丁清償其應分擔部分30萬元之債務後，丁即不得再向甲請求尚未清償之60萬元", "丁向乙請求清償全部債務時，乙得以甲對丁之90萬元債權，向丁主張抵銷", "丙提起請求確認對丁所負連帶債務不存在訴訟，丙敗訴之確定判決之效力不及於甲、乙", "丁得請求甲為清償之權利之消滅時效完成時，其仍得對乙、丙請求清償90萬元，乙、丙不得拒絕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00069', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於旅遊契約之敘述，何者正確？', '["旅客提供資料供旅行社申辦旅遊相關手續，係旅客之協力義務", "旅客於飯店及景點未準時集合，係未盡協力義務，旅行社逕得終止與旅客之旅遊契約", "團員因口角糾紛致影響旅遊興致，旅行社即得將引起糾紛之旅客送回原出發地", "無論有無終止契約，旅行社均應負擔將旅客送回原出發地之費用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00070', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於承攬人法定抵押權之敘述，何者正確？', '["承攬之工作物，不限於建築物或其他土地上之工作物", "承攬人須於工作完成後，始得請求為抵押權之登記", "承攬契約已經公證者，承攬人得單獨申請抵押權之登記", "就承攬人之全部工作報酬額，承攬人之法定抵押權優先於成立在先之意定抵押權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00071', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲向乙發出「請於收到通知後，儘速回覆是否願以新臺幣（下同）50萬元購買A重型機車」之通 知，收到該通知之乙回覆「願以40萬元購買A」。但甲於收到乙回覆前，卻與丙達成合意訂立A 之買賣契約。下列敘述何者正確？', '["甲對乙應負損害賠償責任", "甲、丙之買賣契約成立", "乙得撤銷甲、丙之買賣契約", "乙不受其所回覆內容之拘束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00072', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何種贈與契約，不得任意撤銷之？', '["未經公證之贈與", "立有字據之贈與", "非履行道德上義務之贈與", "贈與物之權利已經移轉之贈與"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00073', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲因愛貓自家中逃脫，遂於住處之公布欄張貼廣告，聲明如有尋獲其愛貓並通知甲帶回者，將提 供新臺幣(下同)1萬元以表酬謝。下列關於懸賞廣告之敘述，何者錯誤？', '["若乙、丙共同尋獲該貓並通知甲帶回，則由乙、丙兩人共同取得報酬請求權", "若乙不知有廣告，而在無意間尋獲該貓並通知甲帶回，則甲對乙仍有給付報酬之義務", "若甲之廣告定有完成行為之期間，則推定甲拋棄其撤回權", "若甲搜尋數日未果，遂撤回廣告，不料該貓已自行返回甲家，則甲對於乙為尋找該貓善意所受 之損害，應負最高1萬元之賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00074', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者非民法第767條規定之物上請求權類型？', '["所有物返還請求權", "所有物賠償請求權", "所有權妨害排除請求權", "所有權妨害預防請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00075', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲為A地之所有人，乙為B地之所有人，A地與B地均為私用土地。甲在A地種植蘋果樹，蘋 果成熟後自落於B地。關於該自落於B地之蘋果所有權之歸屬，下列敘述何者正確?', '["推定屬於乙所有", "視為屬於乙所有", "屬於甲單獨所有", "屬於甲與乙共有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00076', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '抵押人得就抵押物設定數個普通抵押權，而於抵押物賣得之價金，除法律另有規定外，按各抵押 權成立之次序分配之。此次序亦係一種權利，一般稱之為次序權。下列何種次序權之處分，除抵 押權人之意思或相對人之合意外，另須經其他利害關係人同意後，始得為之？', '["為特定抵押權人之利益，讓與其抵押權之次序", "為特定後次序抵押權人之利益，拋棄其抵押權之次序", "為全體後次序抵押權人之利益，拋棄其抵押權之次序", "同一抵押物上之數抵押權人，就其抵押權之次序互換 20320 20420"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
